#include <iostream>
#include <string>

int main() {
    std::string s;
    std::cin >> s;
    int left = 0, right = s.length() - 1;
    while (left < right) {
        if (s[left] != s[right]) {
            std::cout << "No" << std::endl;
            return 0;
        }
        left++;
        right--;
    }
    std::cout << "Yes" << std::endl;
    return 0;
}
